using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Tool implementations --------------------------------------------------------

/// <summary>Tools the research agent can invoke during its agentic loop.</summary>
static class ResearchTools
{
    private static readonly HttpClient s_http = new();
    private static readonly List<string> s_notes = [];

    [Description("Search the web for a query and return a summary of the top results. Use this to gather information on a topic.")]
    public static async Task<string> WebSearch(
        [Description("The search query")] string query)
    {
        Console.ForegroundColor = ConsoleColor.DarkCyan;
        Console.WriteLine($"  🔍 Searching: {query}");
        Console.ResetColor();

        try
        {
            // Use DuckDuckGo instant-answer API (no key required)
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
            var json = await s_http.GetStringAsync(url);
            using var doc = JsonDocument.Parse(json);
            var root = doc.RootElement;

            var results = new List<string>();

            // Abstract / main answer
            var abs = root.GetProperty("Abstract").GetString();
            if (!string.IsNullOrWhiteSpace(abs))
                results.Add($"Summary: {abs}");

            // Related topics
            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var topic in topics.EnumerateArray().Take(5))
                {
                    var text = topic.TryGetProperty("Text", out var t) ? t.GetString() : null;
                    if (!string.IsNullOrWhiteSpace(text))
                        results.Add($"- {text}");
                }
            }

            return results.Count > 0
                ? string.Join("\n", results)
                : $"No detailed results found for '{query}'. Try rephrasing the search.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Save a research note. Use this to record key findings as you research.")]
    public static string SaveNote(
        [Description("The note content to save")] string note)
    {
        s_notes.Add(note);
        Console.ForegroundColor = ConsoleColor.DarkYellow;
        Console.WriteLine($"  📝 Note saved ({s_notes.Count} total)");
        Console.ResetColor();
        return $"Note saved. You now have {s_notes.Count} note(s).";
    }

    [Description("Retrieve all saved research notes so far.")]
    public static string GetNotes()
    {
        if (s_notes.Count == 0)
            return "No notes saved yet.";

        Console.ForegroundColor = ConsoleColor.DarkYellow;
        Console.WriteLine($"  📋 Reading {s_notes.Count} note(s)");
        Console.ResetColor();

        return string.Join("\n---\n",
            s_notes.Select((n, i) => $"Note {i + 1}: {n}"));
    }
}

// --- Main program ----------------------------------------------------------------

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY");
if (string.IsNullOrEmpty(apiKey))
{
    Console.ForegroundColor = ConsoleColor.Red;
    Console.WriteLine("Error: Set the OPENAI_API_KEY environment variable.");
    Console.ResetColor();
    return 1;
}

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

IChatClient client = new OpenAIClient(apiKey)
    .GetChatClient(model)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

var tools = new ChatOptions
{
    Tools =
    [
        AIFunctionFactory.Create(ResearchTools.WebSearch),
        AIFunctionFactory.Create(ResearchTools.SaveNote),
        AIFunctionFactory.Create(ResearchTools.GetNotes),
    ],
};

var systemPrompt = """
    You are a research agent. When the user gives you a topic:
    1. Use the WebSearch tool multiple times with different queries to gather broad information.
    2. Use SaveNote to record important findings as you go.
    3. Use GetNotes to review what you have collected.
    4. After thorough research, provide a well-structured summary with key facts, 
       different perspectives, and references to what you found.
    Be thorough — make at least 3 searches before summarising.
    """;

Console.ForegroundColor = ConsoleColor.Green;
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       🔬 Research Agent Ready        ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.ResetColor();
Console.WriteLine("Enter a topic to research (or 'quit' to exit):\n");

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Topic > ");
    Console.ResetColor();

    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    Console.WriteLine();

    var messages = new List<ChatMessage>
    {
        new(ChatRole.System, systemPrompt),
        new(ChatRole.User, $"Research this topic and provide a summary: {topic}"),
    };

    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine("Researching — this may take a moment...\n");
    Console.ResetColor();

    var response = await client.GetResponseAsync(messages, tools);

    Console.ForegroundColor = ConsoleColor.White;
    Console.WriteLine("\n── Research Summary ────────────────────────────────\n");
    Console.ResetColor();
    Console.WriteLine(response.Text);
    Console.WriteLine("\n────────────────────────────────────────────────────\n");
}

Console.WriteLine("Goodbye!");
return 0;

