using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Tool implementations --------------------------------------------------------

/// <summary>Tools the research agent can invoke during its agentic loop.</summary>
static class ResearchTools
{
    private static readonly HttpClient s_http = new();
    private static readonly List<string> s_notes = [];

    [Description("Search the web for a query and return a summary of the top results. Use this to gather information on a topic.")]
    public static async Task<string> WebSearch(
        [Description("The search query")] string query)
    {
        Console.ForegroundColor = ConsoleColor.DarkCyan;
        Console.WriteLine($"  🔍 Searching: {query}");
        Console.ResetColor();

        try
        {
            // Use DuckDuckGo instant-answer API (no key required)
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
            var json = await s_http.GetStringAsync(url);
            using var doc = JsonDocument.Parse(json);
            var root = doc.RootElement;

            var results = new List<string>();

            // Abstract / main answer
            var abs = root.GetProperty("Abstract").GetString();
            if (!string.IsNullOrWhiteSpace(abs))
                results.Add($"Summary: {abs}");

            // Related topics
            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var topic in topics.EnumerateArray().Take(5))
                {
                    var text = topic.TryGetProperty("Text", out var t) ? t.GetString() : null;
                    if (!string.IsNullOrWhiteSpace(text))
                        results.Add($"- {text}");
                }
            }

            return results.Count > 0
                ? string.Join("\n", results)
                : $"No detailed results found for '{query}'. Try rephrasing the search.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Save a research note. Use this to record key findings as you research.")]
    public static string SaveNote(
        [Description("The note content to save")] string note)
    {
        s_notes.Add(note);
        Console.ForegroundColor = ConsoleColor.DarkYellow;
        Console.WriteLine($"  📝 Note saved ({s_notes.Count} total)");
        Console.ResetColor();
        return $"Note saved. You now have {s_notes.Count} note(s).";
    }

    [Description("Retrieve all saved research notes so far.")]
    public static string GetNotes()
    {
        if (s_notes.Count == 0)
            return "No notes saved yet.";

        Console.ForegroundColor = ConsoleColor.DarkYellow;
        Console.WriteLine($"  📋 Reading {s_notes.Count} note(s)");
        Console.ResetColor();

        return string.Join("\n---\n",
            s_notes.Select((n, i) => $"Note {i + 1}: {n}"));
    }
}

// --- Main program ----------------------------------------------------------------

